+    #[test]
+    fn test_compute_spec_hash_deterministic() {
+        use crate::core::SkillSpec;
+
+        let spec = SkillSpec::new("test-skill", "Test Skill");
+
+        let hash1 = compute_spec_hash(&spec).unwrap();
+        let hash2 = compute_spec_hash(&spec).unwrap();
